import azure.functions as func
from azure.extensions.cors import CORSCottage

def main(req: func.HttpRequest) -> func.HttpResponse:
    cors = CORSCottage()
    cors.add_allow_origin("*")
    cors.add_expose_headers('Access-Control-Allow-Origin')
    cors.add_header('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE,OPTIONS')
    cors.add_header('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    cors.apply_to_func(main)

    if req.method == "OPTIONS":
        return func.Response(can_modify_response=True)

    # Your logic here to handle requests
    return func.HttpResponse(
        f"{req.method} {req.url} HTTP/{req.http_version}",
        status_code=200
    )